import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are Mounib's AI Assistant. You help visitors learn about Mounib's professional profile.
Mounib is a Senior Creative Developer with expertise in React, TypeScript, and AI integrations.
Skills: React, Next.js, TypeScript, Tailwind, Node.js, Gemini API.
Experience: Senior Frontend Architect at Quantum Tech Solutions.
Projects: Solaris AI, Nova Commerce, Aura Health.
Be professional, friendly, and concise. If you don't know something about Mounib, politely mention that you focus on his professional background.
`;

export async function getAssistantResponse(prompt: string) {
  try {
    // Initializing right before the call as recommended for dynamic environments
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        maxOutputTokens: 500,
      },
    });

    if (!response.text) {
      throw new Error("No response text returned from Gemini");
    }

    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I'm having a little trouble connecting to my brain right now. Please try again in a moment!";
  }
}

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  define: {
    'process.env': process.env
  }
});

