import React, { useEffect, useMemo, useRef, useState } from "react";
import { motion, useScroll, useTransform } from "framer-motion";
import { cn } from "../../lib/utils";

export const MacbookScroll = ({
  src,
  showGradient,
  title,
  badge,
}: {
  src?: string;
  showGradient?: boolean;
  title?: string | React.ReactNode;
  badge?: React.ReactNode;
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start start", "end end"],
  });

  const [windowWidth, setWindowWidth] = useState(0);

  useEffect(() => {
    if (typeof window !== "undefined") {
      setWindowWidth(window.innerWidth);
      const handleResize = () => setWindowWidth(window.innerWidth);
      window.addEventListener("resize", handleResize);
      return () => window.removeEventListener("resize", handleResize);
    }
  }, []);

  const scaleX = useTransform(scrollYProgress, [0, 0.3], [1.2, 1]);
  const scaleY = useTransform(scrollYProgress, [0, 0.3], [1.5, 1]);
  const translate = useTransform(scrollYProgress, [0, 0.3], [0, 150]);
  const rotate = useTransform(scrollYProgress, [0.1, 0.12, 0.3], [-28, -28, 0]);
  const textOpacity = useTransform(scrollYProgress, [0, 0.15], [1, 0]);
  const containerScale = useTransform(scrollYProgress, [0, 0.3], [1, 0.9]);

  return (
    <div
      ref={containerRef}
      className="min-h-[200vh] flex flex-col items-center py-0 md:py-80 justify-start flex-shrink-0 [perspective:800px] transform md:scale-100 scale-[0.35] sm:scale-50"
    >
      <motion.h2
        style={{ opacity: textOpacity }}
        className="text-gray-100 text-3xl font-bold mb-20 text-center font-display"
      >
        {title || (
          <span>
            Crafting Digital Excellence <br /> No kidding.
          </span>
        )}
      </motion.h2>

      {/* Macbook Area */}
      <motion.div
        style={{
          scaleX,
          scaleY,
          rotateX: rotate,
          translateY: translate,
          scale: containerScale,
        }}
        className="h-fit w-fit relative flex flex-col items-center justify-center"
      >
        {/* Lid Background */}
        <div className="absolute inset-0 bg-[#272729] rounded-2xl" />

        {/* Screen */}
        <div className="relative h-[480px] w-[800px] bg-[#010101] rounded-2xl p-2 border-2 border-[#171717] shadow-2xl">
          <div className="relative h-full w-full bg-[#050505] rounded-lg overflow-hidden">
            {src ? (
              <img src={src} className="h-full w-full object-cover object-top" alt="Macbook Screen" />
            ) : (
              <div className="h-full w-full bg-gradient-to-br from-brand-900/20 to-purple-900/20 flex items-center justify-center">
                 <div className="text-brand-500 font-display text-4xl font-bold opacity-20">MOUNIB.DEV</div>
              </div>
            )}

            {showGradient && (
              <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent" />
            )}
          </div>
        </div>

        {/* Keyboard / Base */}
        <div className="h-[20px] w-[820px] bg-[#272729] rounded-t-lg relative z-10 -mt-2 shadow-xl" />
        <div className="h-[480px] w-[820px] bg-[#1d1d1f] rounded-b-2xl p-8 relative shadow-2xl">
           {/* Trackpad */}
           <div className="absolute left-1/2 -translate-x-1/2 bottom-8 w-[300px] h-[180px] bg-[#272729] rounded-xl border border-white/5" />

           {/* Keys Mockup */}
           <div className="grid grid-cols-14 gap-2 opacity-50">
             {Array.from({length: 60}).map((_, i) => (
               <div key={i} className="h-8 w-8 bg-[#272729] rounded-md border border-white/5" />
             ))}
           </div>
        </div>

        {badge && (
          <div className="absolute -left-12 top-1/2 -translate-y-1/2 z-50">
            {badge}
          </div>
        )}
      </motion.div>
    </div>
  );
};

