export default function Testimonials() {
  const [cardSize, setCardSize] = useState(380);
  const [testimonialsList, setTestimonialsList] = useState(testimonials);

  const handleMove = (steps: number) => {
    const newList = [...testimonialsList];
    if (steps > 0) {
      for (let i = steps; i > 0; i--) {
        const item = newList.shift();
        if (!item) return;
        newList.push({ ...item, tempId: Math.random() });
      }
    } else {
      for (let i = steps; i < 0; i++) {
        const item = newList.pop();
        if (!item) return;
        newList.unshift({ ...item, tempId: Math.random() });
      }
    }
    setTestimonialsList(newList);
  };

  useEffect(() => {
    const updateSize = () => {
      setCardSize(window.innerWidth < 640 ? 300 : 380);
    };
    updateSize();
    window.addEventListener("resize", updateSize);
    return () => window.removeEventListener("resize", updateSize);
  }, []);

  return (
    <section className="relative w-full h-[700px] overflow-hidden bg-gray-950/50 py-24">
      <div className="absolute top-0 left-1/2 -translate-x-1/2 text-center z-20">
        <h2 className="text-sm font-bold tracking-[0.3em] uppercase text-brand-500 mb-4">Social Proof</h2>
        <h3 className="font-display text-4xl font-bold">Client <span className="text-gradient">Endorsements</span></h3>
      </div>

      <div className="relative h-full flex items-center justify-center">
        {testimonialsList.map((testimonial, index) => {
          const position = index - Math.floor(testimonialsList.length / 2);
          return (
            <TestimonialCard
              key={testimonial.tempId}
              testimonial={testimonial}
              handleMove={handleMove}
              position={position}
              cardSize={cardSize}
            />
          );
        })}
      </div>

      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex gap-4 z-30">
        <button
          onClick={() => handleMove(-1)}
          className="w-14 h-14 glass rounded-full flex items-center justify-center hover:bg-brand-500 hover:text-white transition-all"
        >
          <ChevronLeft />
        </button>
        <button
          onClick={() => handleMove(1)}
          className="w-14 h-14 glass rounded-full flex items-center justify-center hover:bg-brand-500 hover:text-white transition-all"
        >
          <ChevronRight />
        </button>
      </div>
    </section>
  );
}

