const NetworkTopology = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;
    let nodes: NetworkNode[] = [];
    const nodeCount = 35;
    const connectionDistance = 200;

    type NodeType = 'router' | 'switch' | 'pc' | 'terminal';

    class NetworkNode {
      x: number;
      y: number;
      vx: number;
      vy: number;
      type: NodeType;
      id: string;

      constructor(width: number, height: number) {
        this.x = Math.random() * width;
        this.y = Math.random() * height;
        this.vx = (Math.random() - 0.5) * 0.4;
        this.vy = (Math.random() - 0.5) * 0.4;

        const types: NodeType[] = ['router', 'switch', 'pc', 'terminal'];
        this.type = types[Math.floor(Math.random() * types.length)];
        this.id = `${this.type.slice(0, 2).toUpperCase()}-${Math.floor(Math.random() * 999)}`;
      }

      update(width: number, height: number) {
        this.x += this.vx;
        this.y += this.vy;
        if (this.x < 0 || this.x > width) this.vx *= -1;
        if (this.y < 0 || this.y > height) this.vy *= -1;
      }

      draw(ctx: CanvasRenderingContext2D) {
        ctx.save();
        ctx.translate(this.x, this.y);
        ctx.font = '10px monospace';
        ctx.fillStyle = 'rgba(14, 165, 233, 0.7)';

        // Render specific hardware shapes
        if (this.type === 'router') {
          // Hexagon Router
          ctx.beginPath();
          for (let i = 0; i < 6; i++) {
            ctx.lineTo(10 * Math.cos(i * Math.PI / 3), 10 * Math.sin(i * Math.PI / 3));
          }
          ctx.closePath();
          ctx.strokeStyle = '#0ea5e9';
          ctx.stroke();
          ctx.fillText('RT', 12, 4);
        } else if (this.type === 'switch') {
          // Square Switch
          ctx.strokeRect(-8, -8, 16, 16);
          ctx.fillStyle = 'rgba(14, 165, 233, 0.2)';
          ctx.fillRect(-8, -8, 16, 16);
          ctx.fillText('SW', 12, 4);
        } else if (this.type === 'pc') {
          // Monitor PC
          ctx.strokeRect(-10, -8, 20, 14);
          ctx.beginPath();
          ctx.moveTo(-4, 6);
          ctx.lineTo(4, 6);
          ctx.lineTo(6, 10);
          ctx.lineTo(-6, 10);
          ctx.closePath();
          ctx.stroke();
          ctx.fillText('PC', 14, 4);
        } else {
          // Terminal
          ctx.strokeRect(-8, -10, 16, 20);
          ctx.beginPath();
          ctx.moveTo(-4, -4);
          ctx.lineTo(0, 0);
          ctx.lineTo(-4, 4);
          ctx.stroke();
          ctx.fillText('TERM', 12, 4);
        }

        ctx.restore();
      }
    }

    const init = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      nodes = [];
      for (let i = 0; i < nodeCount; i++) {
        nodes.push(new NetworkNode(canvas.width, canvas.height));
      }
    };

    const animate = (time: number) => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      for (let i = 0; i < nodes.length; i++) {
        nodes[i].update(canvas.width, canvas.height);
        nodes[i].draw(ctx);

        for (let j = i + 1; j < nodes.length; j++) {
          const dx = nodes[i].x - nodes[j].x;
          const dy = nodes[i].y - nodes[j].y;
          const distance = Math.sqrt(dx * dx + dy * dy);

          if (distance < connectionDistance) {
            // Draw link
            ctx.beginPath();
            ctx.moveTo(nodes[i].x, nodes[i].y);
            ctx.lineTo(nodes[j].x, nodes[j].y);
            ctx.strokeStyle = `rgba(14, 165, 233, ${0.15 * (1 - distance / connectionDistance)})`;
            ctx.lineWidth = 1;
            ctx.setLineDash([5, 5]);
            ctx.stroke();
            ctx.setLineDash([]);

            // Packet pulse simulation
            const pulsePos = (time * 0.1) % 1;
            const px = nodes[i].x + (nodes[j].x - nodes[i].x) * pulsePos;
            const py = nodes[i].y + (nodes[j].y - nodes[i].y) * pulsePos;

            ctx.beginPath();
            ctx.arc(px, py, 1.5, 0, Math.PI * 2);
            ctx.fillStyle = `rgba(14, 165, 233, ${0.8 * (1 - distance / connectionDistance)})`;
            ctx.fill();
          }
        }
      }
      animationFrameId = requestAnimationFrame(animate);
    };

    window.addEventListener('resize', init);
    init();
    requestAnimationFrame(animate);

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener('resize', init);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="absolute inset-0 z-0 opacity-50 pointer-events-none"
    />
  );
};

