                <div className="flex flex-col">
                  <span className="text-[12px] font-bold text-emerald-400 uppercase tracking-[0.2em] leading-none">Net-Watcher v4.0</span>
                  <span className="text-[8px] text-emerald-500/50 font-mono mt-1 uppercase">Protocol: ICMP-Secure</span>
                </div>
              </div>
              <div className="flex items-center gap-2">
                <div className="h-1.5 w-16 bg-emerald-500/10 rounded-full overflow-hidden">
                  <motion.div 
