import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { cn } from '../lib/utils';

interface TestimonialsProps {
  content: {
    badge: string;
    title: string;
    titleHighlight: string;
    list: {
      tempId: number;
      testimonial: string;
      by: string;
      imgSrc: string;
    }[];
  }
}

interface TestimonialCardProps {
  position: number;
  testimonial: {
      tempId: number;
      testimonial: string;
      by: string;
      imgSrc: string;
  };
  handleMove: (steps: number) => void;
  cardSize: number;
}

const TestimonialCard: React.FC<TestimonialCardProps> = ({ 
  position, 
  testimonial, 
  handleMove, 
  cardSize 
}) => {
  const isCenter = position === 0;

  return (
    <div
      onClick={() => handleMove(position)}
      className={cn(
        "absolute left-1/2 top-1/2 cursor-pointer border-2 p-10 transition-all duration-700 ease-in-out",
        isCenter 
          ? "z-10 bg-brand-600 text-white border-brand-400" 
          : "z-0 bg-gray-900 text-gray-400 border-white/5 hover:border-brand-500/50"
      )}
      style={{
        width: cardSize,
        height: cardSize,
        clipPath: `polygon(40px 0%, calc(100% - 40px) 0%, 100% 40px, 100% 100%, calc(100% - 40px) 100%, 40px 100%, 0 100%, 0 0)`,
        transform: `
          translate(-50%, -50%) 
          translateX(${(cardSize / 1.3) * position}px)
          translateY(${isCenter ? -30 : position % 2 ? 10 : -10}px)
          rotate(${isCenter ? 0 : position % 2 ? 3 : -3}deg)
          scale(${isCenter ? 1 : 0.85})
        `,
        boxShadow: isCenter ? "0px 20px 50px rgba(16, 185, 129, 0.3)" : "none"
      }}
    >
      <img
        src={testimonial.imgSrc}
        alt={testimonial.by}
        className="mb-6 h-14 w-14 rounded-xl object-cover border-2 border-white/10"
      />
      <h3 className={cn(
        "text-lg md:text-xl font-display font-bold leading-snug",
        isCenter ? "text-white" : "text-gray-300"
      )}>
        "{testimonial.testimonial}"
      </h3>
      <p className={cn(
        "absolute bottom-10 left-10 right-10 text-xs font-bold uppercase tracking-widest",
        isCenter ? "text-white/60" : "text-gray-500"
      )}>
        — {testimonial.by}
      </p>
    </div>
  );
};

export default function Testimonials({ content }: TestimonialsProps) {
  const [cardSize, setCardSize] = useState(380);
  const [testimonialsList, setTestimonialsList] = useState(content.list);

  // Update list when content changes (language switch)
  useEffect(() => {
    setTestimonialsList(content.list);
  }, [content]);

  const handleMove = (steps: number) => {
    const newList = [...testimonialsList];
    if (steps > 0) {
      for (let i = steps; i > 0; i--) {
        const item = newList.shift();
        if (!item) return;
        newList.push({ ...item, tempId: Math.random() });
      }
    } else {
      for (let i = steps; i < 0; i++) {
        const item = newList.pop();
        if (!item) return;
        newList.unshift({ ...item, tempId: Math.random() });
      }
    }
    setTestimonialsList(newList);
  };

  useEffect(() => {
    const updateSize = () => {
      setCardSize(window.innerWidth < 640 ? 300 : 380);
    };
    updateSize();
    window.addEventListener("resize", updateSize);
    return () => window.removeEventListener("resize", updateSize);
  }, []);

  return (
    <section className="relative w-full h-[700px] overflow-hidden bg-gray-950/50 py-24">
      {/* Top Fade Overlay */}
      <div className="absolute top-0 left-0 w-full h-32 bg-gradient-to-b from-[#030712] to-transparent z-10 pointer-events-none" />

      <div className="absolute top-12 left-1/2 -translate-x-1/2 text-center z-20">
        <h2 className="text-sm font-bold tracking-[0.3em] uppercase text-brand-500 mb-4">{content.badge}</h2>
        <h3 className="font-display text-4xl font-bold">{content.title} <span className="text-gradient">{content.titleHighlight}</span></h3>
      </div>

      <div className="relative h-full flex items-center justify-center">
        {testimonialsList.map((testimonial, index) => {
          const position = index - Math.floor(testimonialsList.length / 2);
          return (
            <TestimonialCard
              key={testimonial.tempId}
              testimonial={testimonial}
              handleMove={handleMove}
              position={position}
              cardSize={cardSize}
            />
          );
        })}
      </div>

      <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex gap-4 z-30">
        <button
          onClick={() => handleMove(-1)}
          className="w-14 h-14 glass rounded-full flex items-center justify-center hover:bg-brand-500 hover:text-white transition-all"
        >
          <ChevronLeft />
        </button>
        <button
          onClick={() => handleMove(1)}
          className="w-14 h-14 glass rounded-full flex items-center justify-center hover:bg-brand-500 hover:text-white transition-all"
        >
          <ChevronRight />
        </button>
      </div>
    </section>
  );
}

import React, { useEffect, useRef } from 'react';

const MatrixBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = canvas.width = window.innerWidth;
    let height = canvas.height = window.innerHeight;

    // Characters to display (mix of binary, hex, and code symbols)
    const chars = '01{}[]<>/\\*!@#$%=?&';
    const charArray = chars.split('');

    const fontSize = 16;
    const columns = Math.floor(width / fontSize);

    const drops: number[] = [];
    for (let i = 0; i < columns; i++) {
      drops[i] = Math.random() * -100; // Start at random heights above screen
    }

    const draw = () => {
      // Fade out previous frame to create trail effect
      ctx.fillStyle = 'rgba(3, 7, 18, 0.1)'; 
      ctx.fillRect(0, 0, width, height);

      ctx.font = `${fontSize}px "JetBrains Mono", monospace`;

      for (let i = 0; i < drops.length; i++) {
        const text = charArray[Math.floor(Math.random() * charArray.length)];

        // Varying colors for depth
        const isBright = Math.random() > 0.95;
        if (isBright) {
           ctx.fillStyle = '#34d399'; // Bright Emerald
           ctx.shadowBlur = 5;
           ctx.shadowColor = '#34d399';
        } else {
           ctx.fillStyle = '#065f46'; // Darker Emerald
           ctx.shadowBlur = 0;
        }

        ctx.fillText(text, i * fontSize, drops[i] * fontSize);

        // Reset drop to top randomly
        if (drops[i] * fontSize > height && Math.random() > 0.975) {
          drops[i] = 0;
        }

        drops[i]++;
      }
    };

    const interval = setInterval(draw, 50);

    const handleResize = () => {
      width = canvas.width = window.innerWidth;
      height = canvas.height = window.innerHeight;
      // Recalculate columns
      const newColumns = Math.floor(width / fontSize);
      // Initialize new columns
      for (let i = drops.length; i < newColumns; i++) {
        drops[i] = Math.random() * -100;
      }
    };

    window.addEventListener('resize', handleResize);

    return () => {
      clearInterval(interval);
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full opacity-20 pointer-events-none mix-blend-screen" />;
};

export default MatrixBackground;

import React, { useEffect, useRef } from 'react';

const MatrixBackground: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let width = canvas.width = window.innerWidth;
    let height = canvas.height = window.innerHeight;

    // Characters: Binary + Tech Symbols
    const chars = '01<>/\\|{}[]*&^%$#@!+=';
    const charArray = chars.split('');

    const fontSize = 16;
    const columns = Math.ceil(width / fontSize);

    const drops: number[] = [];
    for (let i = 0; i < columns; i++) {
      drops[i] = Math.random() * -100;
    }

    const draw = () => {
      // Create trailing effect with low opacity fill
      ctx.fillStyle = 'rgba(2, 6, 23, 0.1)'; // Dark slate, low opacity for trails
      ctx.fillRect(0, 0, width, height);

      ctx.font = `bold ${fontSize}px "JetBrains Mono", monospace`;

      for (let i = 0; i < drops.length; i++) {
        const text = charArray[Math.floor(Math.random() * charArray.length)];

        // Randomly pick color for "glitch" effect
        const random = Math.random();
        if (random > 0.98) {
           ctx.fillStyle = '#fff'; // White glint
        } else if (random > 0.9) {
           ctx.fillStyle = '#34d399'; // Bright Emerald
        } else if (random > 0.8) {
           ctx.fillStyle = '#2dd4bf'; // Teal
        } else {
           ctx.fillStyle = '#059669'; // Standard Emerald
        }

        const x = i * fontSize;
        const y = drops[i] * fontSize;

        ctx.fillText(text, x, y);

        // Reset drop
        if (y > height && Math.random() > 0.975) {
          drops[i] = 0;
        }

        drops[i]++;
      }
    };

    const interval = setInterval(draw, 50);

    const handleResize = () => {
      width = canvas.width = window.innerWidth;
      height = canvas.height = window.innerHeight;
      const newColumns = Math.ceil(width / fontSize);
      // Preserve existing drops if possible, extend if wider
      if (newColumns > drops.length) {
         for (let i = drops.length; i < newColumns; i++) {
             drops[i] = Math.random() * -100;
         }
      }
    };

    window.addEventListener('resize', handleResize);

    return () => {
      clearInterval(interval);
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="absolute inset-0 w-full h-full pointer-events-none opacity-40 z-0" 
      style={{ filter: 'drop-shadow(0 0 4px rgba(52, 211, 153, 0.5))' }}
    />
  );
};

