const ContactForm: React.FC<ContactFormProps> = ({ content }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    referral: '',
    message: ''
  });
  const [status, setStatus] = useState<'idle' | 'submitting' | 'success' | 'error'>('idle');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('submitting');

    try {
      const res = await fetch("https://formsubmit.co/ajax/mounibalioua18@gmail.com", {
        method: "POST",
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          name: formData.name,
          email: formData.email,
          "How did you hear about me?": formData.referral,
          message: formData.message,
          _subject: `New Portfolio Contact from ${formData.name}`,
          _template: "table",
          _captcha: "false"
        })
      });

      if (res.ok) {
        setStatus('success');
        setFormData({ name: '', email: '', referral: '', message: '' });
        // Reset status after a few seconds if desired, but keeping success message is usually better for confirmation
      } else {
        setStatus('error');
      }
    } catch (error) {
      setStatus('error');
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
