import { Client, Databases } from 'appwrite';

// Helper to get env vars if available (Vite standard)
const getEnv = (key: string) => {
  // @ts-ignore
  return import.meta.env?.[key] || '';
}

export const APPWRITE_CONFIG = {
  ENDPOINT: getEnv('VITE_APPWRITE_ENDPOINT') || 'https://cloud.appwrite.io/v1',

  // REPLACE THESE WITH YOUR ACTUAL IDS IF NOT USING .env FILE
  PROJECT_ID: getEnv('VITE_APPWRITE_PROJECT_ID') || 'YOUR_PROJECT_ID',           
  DATABASE_ID: getEnv('VITE_APPWRITE_DATABASE_ID') || 'YOUR_DATABASE_ID',         
  COLLECTION_ID: getEnv('VITE_APPWRITE_COLLECTION_ID') || 'YOUR_COLLECTION_ID'      
};

export const isAppwriteConfigured = () => {
  return (
    APPWRITE_CONFIG.PROJECT_ID !== 'YOUR_PROJECT_ID' &&
    APPWRITE_CONFIG.DATABASE_ID !== 'YOUR_DATABASE_ID' &&
    APPWRITE_CONFIG.COLLECTION_ID !== 'YOUR_COLLECTION_ID'
  );
};

const client = new Client();

client
    .setEndpoint(APPWRITE_CONFIG.ENDPOINT)
    .setProject(APPWRITE_CONFIG.PROJECT_ID);

export const databases = new Databases(client);

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Send, CheckCircle2, Loader2, AlertCircle, Settings } from 'lucide-react';
import { LiquidButton } from './ui/LiquidButton';
import { databases, APPWRITE_CONFIG, isAppwriteConfigured } from '../lib/appwrite';
import { ID } from 'appwrite';

interface ContactFormProps {
  content: {
    name: string;
    email: string;
    subject: string;
    message: string;
    namePlaceholder: string;
    emailPlaceholder: string;
    subjectPlaceholder: string;
    messagePlaceholder: string;
    btn: string;
    success: string;
  }
}

const ContactForm: React.FC<ContactFormProps> = ({ content }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    referral: '',
    message: ''
  });
  const [status, setStatus] = useState<'idle' | 'submitting' | 'success' | 'error' | 'config_error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Check if configured before sending
    if (!isAppwriteConfigured()) {
      setStatus('config_error');
      setErrorMessage("Missing Appwrite IDs in lib/appwrite.ts");
      return;
    }

    setStatus('submitting');
    setErrorMessage('');

    try {
      await databases.createDocument(
        APPWRITE_CONFIG.DATABASE_ID,
        APPWRITE_CONFIG.COLLECTION_ID,
        ID.unique(),
        {
          name: formData.name,
          email: formData.email,
          referral: formData.referral,
          message: formData.message,
        }
      );

      setStatus('success');
      setFormData({ name: '', email: '', referral: '', message: '' });

    } catch (error: any) {
      console.error("Appwrite submission failed:", error);
      setStatus('error');
      // Show a more helpful message if it's a permission issue
      if (error?.code === 401) {
        setErrorMessage("Permission denied. Check Appwrite Collection permissions (Role: Any).");
      } else if (error?.code === 404) {
        setErrorMessage("Collection or Database ID not found.");
      } else {
        setErrorMessage(error?.message || "Something went wrong. Check console.");
      }
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="w-full max-w-2xl mx-auto">
      <form 
        onSubmit={handleSubmit} 
        className="space-y-6 text-left"
      >
        <div className="grid md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-xs font-bold uppercase tracking-widest text-gray-500 ml-2">{content.name}</label>
            <input
              required
              type="text"
              name="name"
              value={formData.name}
              onChange={handleChange}
              placeholder={content.namePlaceholder}
              disabled={status === 'submitting' || status === 'success'}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:outline-none focus:border-brand-500/50 focus:ring-1 focus:ring-brand-500/20 transition-all placeholder:text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed"
            />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-bold uppercase tracking-widest text-gray-500 ml-2">{content.email}</label>
            <input
              required
              type="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder={content.emailPlaceholder}
              disabled={status === 'submitting' || status === 'success'}
              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:outline-none focus:border-brand-500/50 focus:ring-1 focus:ring-brand-500/20 transition-all placeholder:text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed"
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-xs font-bold uppercase tracking-widest text-gray-500 ml-2">{content.subject}</label>
          <input
            required
            type="text"
            name="referral"
            value={formData.referral}
            onChange={handleChange}
            placeholder={content.subjectPlaceholder}
            disabled={status === 'submitting' || status === 'success'}
            className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:outline-none focus:border-brand-500/50 focus:ring-1 focus:ring-brand-500/20 transition-all placeholder:text-gray-600 disabled:opacity-50 disabled:cursor-not-allowed"
          />
        </div>

        <div className="space-y-2">
          <label className="text-xs font-bold uppercase tracking-widest text-gray-500 ml-2">{content.message}</label>
          <textarea
            required
            name="message"
            rows={5}
            value={formData.message}
            onChange={handleChange}
            placeholder={content.messagePlaceholder}
            disabled={status === 'submitting' || status === 'success'}
            className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 text-white focus:outline-none focus:border-brand-500/50 focus:ring-1 focus:ring-brand-500/20 transition-all placeholder:text-gray-600 resize-none disabled:opacity-50 disabled:cursor-not-allowed"
          />
        </div>

        <div className="flex flex-col items-center pt-4">
          <LiquidButton 
            type="submit" 
            className={`w-full md:w-auto min-w-[200px] ${status === 'submitting' || status === 'success' ? 'opacity-70 pointer-events-none' : ''}`}
            disabled={status === 'submitting' || status === 'success'}
          >
            {status === 'submitting' ? (
              <span className="flex items-center gap-2">
                <Loader2 size={18} className="animate-spin" /> Sending...
              </span>
            ) : status === 'success' ? (
              <span className="flex items-center gap-2">
                <CheckCircle2 size={18} /> Sent!
              </span>
            ) : status === 'error' ? (
               <span className="flex items-center gap-2">
                <AlertCircle size={18} /> Retry
              </span>
            ) : status === 'config_error' ? (
              <span className="flex items-center gap-2">
               <Settings size={18} /> Config Required
             </span>
           ) : (
              <span className="flex items-center gap-2">
                <Send size={18} /> {content.btn}
              </span>
            )}
          </LiquidButton>

          {status === 'success' && (
            <motion.p
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="mt-4 text-brand-400 text-sm font-medium flex items-center gap-2"
            >
              {content.success}
            </motion.p>
          )}

          {(status === 'error' || status === 'config_error') && (
             <motion.p
             initial={{ opacity: 0, y: 10 }}
             animate={{ opacity: 1, y: 0 }}
             className="mt-4 text-red-400 text-sm font-medium flex items-center gap-2 px-4 py-2 bg-red-500/10 rounded-lg border border-red-500/20"
           >
             {errorMessage || "Submission failed. Please check the console."}
           </motion.p>
          )}
        </div>
      </form>
    </div>
  );
};

export default ContactForm;

